import { format } from "date-fns";

const dataUrl = '/data';

export async function fetchPictures() {
    // Pictures are embedded inside each day's timeline JSON — no separate fetch needed.
    return [];
};

export async function fetchShazams() {
    try {
        const response = await fetch(`${dataUrl}/shazams.json`);
        if (!response.ok) throw new Error('Failed to fetch');
        return await response.json();
    } catch (error) {
        console.error('Error fetching shazams:', error);
    }
};

